// miniprogram/libs/weapp-qrcode.min.js
// QR码生成库封装 - 生产环境请替换为完整的 weapp-qrcode 库
function drawQrcode(options) {
  var canvasId = options.canvasId
  var text = options.text || ''
  var width = options.width || 200
  var height = options.height || 200
  var ctx = wx.createCanvasContext(canvasId)
  // Draw white background
  ctx.setFillStyle('#FFFFFF')
  ctx.fillRect(0, 0, width, height)
  // Draw QR pattern placeholder
  var cellSize = Math.floor(width / 25)
  var hash = 0
  for (var i = 0; i < text.length; i++) {
    hash = ((hash << 5) - hash) + text.charCodeAt(i)
    hash = hash & hash
  }
  for (var row = 0; row < 25; row++) {
    for (var col = 0; col < 25; col++) {
      var val = (hash + row * 31 + col * 37) & 1
      if (val || (row < 7 && col < 7) || (row < 7 && col > 17) || (row > 17 && col < 7)) {
        ctx.setFillStyle('#000000')
        ctx.fillRect(col * cellSize, row * cellSize, cellSize, cellSize)
      }
    }
  }
  ctx.draw(false, function() {
    if (options.callback) options.callback()
  })
}
module.exports = drawQrcode
